import { app, BrowserWindow, dialog, globalShortcut, ipcMain } from "electron";
import { parseArgs } from "node:util";
import { resolve } from "path";
import "source-map-support/register";
import { v7 as uuidv7 } from "uuid";
import getEnv from "./env";
import makeNode from "./node";
import initUpdater from "./updater";
import { generatePrivateKey, privateKeyToAccount } from "viem/accounts";

// This allows TypeScript to pick up the magic constants that's auto-generated by Forge's Webpack
// plugin that tells the Electron app where to look for the Webpack-bundled app code (depending on
// whether you're running in development or production).
declare const MAIN_WINDOW_WEBPACK_ENTRY: string;
declare const MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY: string;

// Handle creating/removing shortcuts on Windows when installing/uninstalling.
if (require("electron-squirrel-startup")) {
  app.quit();
} else {
  const { values: args, positionals } = parseArgs({
    options: {
      path: {
        type: "string",
        default: "",
      },
      "self-test": {
        type: "boolean",
      },
      "self-test-duration": {
        type: "string",
        default: "300000",
      },
    },
  });
  const env = getEnv();
  console.log(
    "starting with: ",
    JSON.stringify({ args, positionals, env }, null, 2),
  );

  app.on("ready", async () => {
    let privateKey: `0x${string}`;
    if (process.env.AQD_ADMIN_ACCOUNT_KEY) {
      privateKey = process.env.AQD_ADMIN_ACCOUNT_KEY as `0x${string}`;
    } else {
      privateKey = generatePrivateKey();
    }
    ipcMain.handle("getPrivateKey", () => privateKey);
    const account = privateKeyToAccount(privateKey);
    const env = {
      AQ_ADMIN_ACCOUNT: account.address.toLowerCase(),
    };
    try {
      if (!args["self-test"]) {
        await start(env);
      } else {
        await runSelfTest(env);
      }
    } catch (e) {
      console.error(e);
      const dialogOpts: Electron.MessageBoxOptions = {
        type: "info",
        buttons: ["Quit Aquareum"],
        title: "Error on Bootup",
        message: "Please report to the Aquareum developers at git.aquareum.tv!",
        detail: e.message + "\n" + e.stack,
      };

      await dialog.showMessageBox(dialogOpts);
      app.quit();
    }
  });

  const makeWindow = async (): Promise<BrowserWindow> => {
    const { isDev } = getEnv();
    let logoFile: string;
    if (isDev) {
      // theoretically cwd is aquareum/js/desktop:
      logoFile = resolve(process.cwd(), "assets", "aquareum-logo.png");
    } else {
      logoFile = resolve(process.resourcesPath, "aquareum-logo.png");
    }
    const window = new BrowserWindow({
      height: 600,
      width: 800,
      icon: logoFile,
      webPreferences: {
        preload: MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY,
      },
      // titleBarStyle: "hidden",
      // titleBarOverlay: true,
    });

    globalShortcut.register("CommandOrControl+Shift+I", () => {
      window.webContents.toggleDevTools();
    });

    globalShortcut.register("CommandOrControl+Shift+R", () => {
      window.webContents.reload();
    });

    window.removeMenu();

    return window;
  };

  const start = async (env: { [k: string]: string }): Promise<void> => {
    initUpdater();
    const { skipNode, nodeFrontend } = getEnv();
    let loadAddr;
    if (!skipNode) {
      const { addr } = await makeNode({ env, autoQuit: true });
      loadAddr = addr;
    }
    const mainWindow = await makeWindow();

    let startPath;
    if (nodeFrontend) {
      startPath = `${loadAddr}${args.path}`;
    } else {
      startPath = `http://127.0.0.1:38081${args.path}`;
    }
    console.log(`opening ${startPath}`);
    mainWindow.loadURL(startPath);
  };

  const delay = (ms: number) => new Promise((r) => setTimeout(r, ms));
  // how much of our time is spent playing for a success?
  const PLAYING_SUCCESS = 0.5;

  const runSelfTest = async (env: { [k: string]: string }): Promise<void> => {
    let exitCode = 0;
    let done = false;
    const { nodeFrontend } = getEnv();
    const { addr, internalAddr, proc } = await makeNode({
      env: {
        AQ_TEST_STREAM: "true",
      },
      autoQuit: false,
    });
    proc.on("exit", () => {
      if (!done) {
        console.log("node exited early, erroring!");
        app.exit(1);
      }
    });
    try {
      const mainWindow = await makeWindow();

      const testId = uuidv7();
      const definitions = [
        {
          name: "hls",
          src: "/hls/stream.m3u8",
        },
        {
          name: "progressive-mp4",
          src: "/stream.mp4",
        },
        {
          name: "progressive-webm",
          src: "/stream.webm",
        },
      ];
      const tests = definitions.map((x) => ({
        name: x.name,
        playerId: `${testId}-${x.name}`,
        src: `${addr}/api/playback/self-test${x.src}`,
        showControls: true,
      }));
      const enc = encodeURIComponent(JSON.stringify(tests));

      console.log(`http://127.0.0.1:38081/multi/${enc}`);

      let load;
      if (nodeFrontend) {
        load = `${addr}/multi/${enc}`;
      } else {
        load = `http://127.0.0.1:38081/multi/${enc}`;
      }
      console.log(`opening ${load}`);
      mainWindow.loadURL(load);

      let foundThumbnail = false;
      const interval = setInterval(async () => {
        const res = await fetch(`${addr}/api/playback/self-test/stream.jpg`);
        if (res.status === 404) {
          console.log("no thumbnail found");
          return;
        }
        if (res.status !== 200) {
          console.log(
            `unexpected http status ${res.status}, failing thumbnail test`,
          );
          clearInterval(interval);
          return;
        }
        const blob = await res.arrayBuffer();
        if (blob.byteLength < 1) {
          console.log("thumbnail was empty :(");
          return;
        }
        console.log("found thumbnail!");
        foundThumbnail = true;
        clearInterval(interval);
      }, 1000);

      await delay(parseInt(args["self-test-duration"]));
      clearInterval(interval);
      const reports = await Promise.all(
        tests.map(async (t) => {
          const res = await fetch(
            `${internalAddr}/player-report/${t.playerId}`,
          );
          const data = (await res.json()) as { [k: string]: number };
          return { ...t, data: data };
        }),
      );
      let failed = false;
      if (!foundThumbnail) {
        console.log("never found a thumbnail, failing test");
        failed = true;
      }
      const percentages = reports.map((report) => {
        let total = 0;
        for (const [state, ms] of Object.entries(report.data)) {
          total += ms;
        }
        const pcts: { [k: string]: number } = { playing: 0 };
        for (const [state, ms] of Object.entries(report.data)) {
          pcts[state] = ms / total;
        }
        if (pcts.playing < PLAYING_SUCCESS) {
          failed = true;
        }
        return { ...report, pcts };
      });
      done = true;
      console.log(JSON.stringify(percentages, null, 2));
      if (failed) {
        console.log("test failed! exiting 1");
        exitCode = 1;
      }
    } catch (e) {
      console.error(`error in self-test: ${e}`);
    } finally {
      proc.kill("SIGTERM");
      app.exit(exitCode);
    }
  };

  // This method will be called when Electron has finished
  // initialization and is ready to create browser windows.
  // Some APIs can only be used after this event occurs.

  // Quit when all windows are closed, except on macOS. There, it's common
  // for applications and their menu bar to stay active until the user quits
  // explicitly with Cmd + Q.
  // app.on("window-all-closed", () => {
  //   if (process.platform !== "darwin") {
  //     app.quit();
  //   }
  // });

  app.on("activate", () => {
    // On OS X it's common to re-create a window in the app when the
    // dock icon is clicked and there are no other windows open.
    // if (BrowserWindow.getAllWindows().length === 0) {
    // }
  });

  // In this file you can include the rest of your app's specific main process
  // code. You can also put them in separate files and import them here.
}
